// src/components/Sidebar.js

import React from 'react';

const menu = [
  { key: 'dashboard', label: 'Dashboard', icon: '🏠' },
  { key: 'agendar', label: 'Agendar Paciente', icon: '🗓️' },
  { key: 'disciplinas', label: 'Disciplinas', icon: '📖' },
  { key: 'pacientes', label: 'Pacientes', icon: '👥' },
  { key: 'alunos', label: 'Alunos', icon: '👤' },
  { key: 'solicitacoes', label: 'Solicitações', icon: '✉️' },
];

const extra = [
  { key: 'config', label: 'Configurações', icon: '⚙️' },
  { key: 'ajuda', label: 'Ajuda', icon: '❓' },
];

export default function Sidebar({ active, onMenuClick }) {
  return (
    <aside className="w-60 min-h-screen bg-white border-r flex flex-col py-4">
      {/* Título/logo */}
      <div className="flex items-center mb-8 px-6">
        <span className="font-extrabold text-xl tracking-tight">✱ PoliUb Atendimento</span>
      </div>
      {/* Menu principal */}
      <nav className="flex-1">
        {menu.map(item => (
          <button
            key={item.key}
            className={`w-full flex items-center px-6 py-3 mb-1 rounded-lg text-left transition 
              ${active === item.key ? 'bg-blue-100 font-bold' : 'hover:bg-gray-100'}
              `}
            onClick={() => onMenuClick(item.key)}
          >
            <span className="mr-3 text-lg">{item.icon}</span>
            <span>{item.label}</span>
          </button>
        ))}
      </nav>
      {/* Separador */}
      <div className="border-t mx-6 my-4" />
      {/* Menu extra */}
      <nav>
        {extra.map(item => (
          <button
            key={item.key}
            className="w-full flex items-center px-6 py-3 rounded-lg text-left transition hover:bg-gray-100"
            onClick={() => onMenuClick(item.key)}
          >
            <span className="mr-3 text-lg">{item.icon}</span>
            <span>{item.label}</span>
          </button>
        ))}
      </nav>
    </aside>
  );
}
